<?phpnamespace App\Repository;use App\Entity\Quartier;use Doctrine\Bundle\DoctrineBundle\Repository\ServiceEntityRepository;use Doctrine\Persistence\ManagerRegistry;/** * @method Quartier|null find($id, $lockMode = null, $lockVersion = null) * @method Quartier|null findOneBy(array $criteria, array $orderBy = null) * @method Quartier[]    findAll() * @method Quartier[]    findBy(array $criteria, array $orderBy = null, $limit = null, $offset = null) */class QuartierRepository extends ServiceEntityRepository{    public function __construct(ManagerRegistry $registry)    {        parent::__construct($registry, Quartier::class);    }    /**     * @param int $cercleId     * @return float|int|mixed|string     */    public function getQuartierByCercleId(int $cercleId)    {        return $this->createQueryBuilder('q')            ->leftJoin('q.commune', 'commune')            ->leftJoin('commune.cercle', 'cercle')            ->where('cercle.id =:cercleId')            ->setParameter('cercleId', $cercleId)            ->orderBy('q.name', 'ASC')            ->getQuery()            ->getResult();    }    /**     * @param $name     * @return float|int|mixed|string     */    public function findQuartierByName($name)    {        $name = '%'.$name.'%';        return $this->createQueryBuilder('q')            ->where('q.name LIKE :name')            ->setParameter('name', $name)            ->getQuery()            ->getResult();    }    // /**    //  * @return Quartier[] Returns an array of Quartier objects    //  */    /*    public function findByExampleField($value)    {        return $this->createQueryBuilder('q')            ->andWhere('q.exampleField = :val')            ->setParameter('val', $value)            ->orderBy('q.id', 'ASC')            ->setMaxResults(10)            ->getQuery()            ->getResult()        ;    }    */    /*    public function findOneBySomeField($value): ?Quartier    {        return $this->createQueryBuilder('q')            ->andWhere('q.exampleField = :val')            ->setParameter('val', $value)            ->getQuery()            ->getOneOrNullResult()        ;    }    */}